const inputDate = $input.first().json.fecha;

console.log('DEBUG - Valor recibido:', {
  valor: inputDate,
  tipo: typeof inputDate,
  esNumero: typeof inputDate === 'number',
  valorString: String(inputDate)
});

if (!inputDate && inputDate !== 0) {
  return [{ json: { fecha_formateada: null, error: 'Fecha vacía' } }];
}

try {
  let dateObj;
  const strValue = String(inputDate).trim();

  // CASO 1: Si es un número pequeño (como 29.0) - probablemente es solo el día
  const numValue = parseFloat(strValue);

  if (!isNaN(numValue) && numValue < 32 && numValue > 0) {
    // Es solo un día (1-31), falta mes y año
    console.log('Parece ser solo un día del mes:', numValue);

    // Si solo tenemos el día, usamos la fecha actual
    const today = new Date();
    const currentYear = today.getFullYear();
    const currentMonth = today.getMonth(); // 0-11

    // Validar día
    const day = Math.floor(numValue);
    if (day < 1 || day > 31) {
      throw new Error(`Día ${day} fuera de rango`);
    }

    dateObj = new Date(currentYear, currentMonth, day);
    console.log('Usando fecha actual con día proporcionado:', dateObj);

  } 
  // CASO 2: Si es un número serial de Google Sheets (grande, > 40000 para fechas recientes)
  else if (!isNaN(numValue) && numValue > 40000) {
    console.log('Parece ser número serial de Google Sheets:', numValue);

    // Convertir serial de Google Sheets a fecha
    // Google Sheets: 1 = 1 enero 1900
    const millisecondsPerDay = 24 * 60 * 60 * 1000;
    const offsetDays = 25569; // Días entre 1900-01-01 y 1970-01-01

    dateObj = new Date((numValue - offsetDays) * millisecondsPerDay);
    console.log('Fecha convertida desde serial:', dateObj);

  }
  // CASO 3: Si es string con formato de fecha
  else if (strValue.includes('/')) {
    console.log('Parece ser fecha con formato DD/MM/YYYY:', strValue);

    const parts = strValue.split('/');
    if (parts.length === 3) {
      const day = parseInt(parts[0], 10);
      const month = parseInt(parts[1], 10) - 1;
      const year = parseInt(parts[2], 10);

      dateObj = new Date(year, month, day);
    }
  }
  // CASO 4: Intentar como fecha ISO
  else {
    dateObj = new Date(strValue);
  }

  // Validar fecha
  if (!dateObj || isNaN(dateObj.getTime())) {
    throw new Error('No se pudo crear una fecha válida');
  }

  // Formatear
  const year = dateObj.getFullYear();
  const month = String(dateObj.getMonth() + 1).padStart(2, '0');
  const day = String(dateObj.getDate()).padStart(2, '0');

  const formattedDate = `${year}-${month}-${day}`;

  console.log('Resultado final:', formattedDate);

  return [{ 
    json: { 
      fecha_original: inputDate,
      fecha_formateada: formattedDate,
      año: year,
      mes: month,
      dia: day,
      timestamp: dateObj.getTime()
    } 
  }];

} catch (error) {
  console.error('Error:', error);
  return [{ 
    json: { 
      fecha_original: inputDate,
      fecha_formateada: null,
      error: error.message 
    } 
  }];
}

