/**
 * Mejora de tabla con estilos directos para mayor compatibilidad
 * Azul cielo en encabezado y borde 1px.
 */
function construirTablaEvaluacion(datos) {
    // Definición de colores
    const azulCielo = "#87CEEB";
    const grisBorde = "#dddddd";

    let html = `
    <table style="width: 100%; border-collapse: collapse; border: 1px solid ${grisBorde}; font-family: Arial, sans-serif; font-size: 13px;">
        <thead>
            <tr style="background-color: ${azulCielo}; color: #333;">
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: left;">Competencia</th>
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: center;">Puntaje</th>
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: center;">%</th>
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: center;">Supervisor</th>
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: center;">Subordinado</th>
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: center;">Par</th>
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: center;">Cliente</th>
                <th style="border: 1px solid ${grisBorde}; padding: 10px; text-align: center;">Autoevaluación</th>
            </tr>
        </thead>
        <tbody>`;

    for (const item of datos) {
        const json = item.json;
        const puntaje = parseFloat(json.puntaje || json.promedio || 0);
        const porcentaje = parseFloat(json.porcentaje || 0);
        const auto = parseFloat(json.auto || json.autoevaluacion || 0);

        html += `
        <tr>
            <td style="border: 1px solid ${grisBorde}; padding: 8px;">${json.competencia || json.nombre || 'N/A'}</td>
            <td style="border: 1px solid ${grisBorde}; padding: 8px; text-align: center; ${obtenerEstiloPuntaje(puntaje)}">
                ${puntaje.toFixed(2)}
            </td>
            <td style="border: 1px solid ${grisBorde}; padding: 8px; text-align: center; ${obtenerEstiloPorcentaje(porcentaje)}">
                ${porcentaje}%
            </td>
            <td style="border: 1px solid ${grisBorde}; padding: 8px; text-align: center;">${json.supervisor || json.jefe || '0.0'}</td>
            <td style="border: 1px solid ${grisBorde}; padding: 8px; text-align: center;">${json.subordinado || '0.0'}</td>
            <td style="border: 1px solid ${grisBorde}; padding: 8px; text-align: center;">${json.par || '0.0'}</td>
            <td style="border: 1px solid ${grisBorde}; padding: 8px; text-align: center;">${json.cliente || '0.0'}</td>
            <td style="border: 1px solid ${grisBorde}; padding: 8px; text-align: center; ${obtenerEstiloAuto(auto)}">
                ${auto.toFixed(1)}
            </td>
        </tr>`;
    }

    html += `</tbody></table>`;
    return html;
}

// Funciones auxiliares con Estilos CSS en línea (In-line styles)
function obtenerEstiloPuntaje(puntaje) {
    if (puntaje >= 4.5) return 'color: #1a7f37; font-weight: bold;';
    if (puntaje >= 3.5) return 'color: #0969da;';
    if (puntaje >= 2.5) return 'color: #9a6700;';
    return 'color: #cf222e;';
}

function obtenerEstiloPorcentaje(porcentaje) {
    if (porcentaje >= 90) return 'color: #1a7f37; font-weight: bold;';
    if (porcentaje >= 70) return 'color: #0969da;';
    return 'color: #cf222e;';
}

function obtenerEstiloAuto(auto) {
    if (auto >= 4.5) return 'background-color: #dafbe1;';
    if (auto >= 3.5) return 'background-color: #ddf4ff;';
    return 'background-color: #fff8c5;';
}

