const items = [];

for (let i = 0; i < $input.all().length; i++) {
  let item = $input.all()[i].json;

  // Si evaluado es un string, parsearlo
  if (typeof item.evaluado === 'string') {
    try {
      // Eliminar saltos de línea y espacios innecesarios
      const cleanedJson = item.evaluado.replace(/\\n/g, '').replace(/\\"/g, '"').trim();
      item.evaluado = JSON.parse(cleanedJson);
    } catch (error) {
      // Si falla, intentar limpiar más
      const fixedJson = item.evaluado
        .replace(/\\n/g, '')
        .replace(/\\t/g, '')
        .replace(/\\r/g, '')
        .replace(/\s+/g, ' ')
        .replace(/\\"/g, '"')
        .replace(/"{/g, '{')
        .replace(/}"/g, '}');

      try {
        item.evaluado = JSON.parse(fixedJson);
      } catch (e) {
        // Si aún falla, dejar el string original
        item.evaluado = item.evaluado.replace(/\\n/g, ' ').replace(/\s+/g, ' ');
      }
    }
  }

  items.push({ json: item });
}

return items;

